// Nur unterstuetzte Dateitypen durchlassen
// und source-Info hinzufuegen

const items = $input.all();
const results = [];
const supported = ['pdf', 'docx', 'doc', 'txt', 'md', 'csv'];

for (const item of items) {
  const name = item.json.name || '';
  const ext = name.split('.').pop().toLowerCase();
  if (!supported.includes(ext)) continue;

  results.push({
    json: {
      source: 'google_drive',
      source_id: item.json.id,
      file_name: item.json.name,
      mime_type: item.json.mimeType || '',
      modified_at: item.json.modifiedTime || '',
      file_path: ''
    }
  });
}

return results;

// Nur weiter wenn Datei noch nicht indexiert
const response = $input.first().json;
const existing = Array.isArray(response) ? response : (response.body || []);

if (existing.length > 0) {
  return []; // Bereits indexiert, ueberspringen
}

// Originalwerte durchreichen
return [$input.first()];

// Text extrahieren + PDF-Splitting fuer Gemini Embedding 2
// Bei gescannten PDFs > 6 Seiten: In 6-Seiten-Bloecke splitten

const items = $input.all();
const results = [];

for (const item of items) {
  const fileName = item.json.file_name || item.json.name || 'unbekannt';
  const ext = fileName.split('.').pop().toLowerCase();
  let text = '';
  let pdfPages = 0;
  let pdfChunksBase64 = [];

  try {
    if (item.binary && item.binary.data) {
      const buffer = await this.helpers.getBinaryDataBuffer(item, 'data');

      if (ext === 'pdf') {
        const pdfParse = require('pdf-parse');
        const pdfData = await pdfParse(buffer);
        text = pdfData.text || '';
        pdfPages = pdfData.numpages || 0;

        if (text.trim().length < 50) {
          text = '[OCR_NEEDED] ' + text;
          const base64Full = buffer.toString('base64');

          if (pdfPages <= 6) {
            pdfChunksBase64.push({ data: base64Full, pages: `1-${pdfPages}`, block_index: 0 });
          } else {
            try {
              const { PDFDocument } = require('pdf-lib');
              const srcDoc = await PDFDocument.load(buffer);
              const totalPages = srcDoc.getPageCount();

              for (let start = 0; start < totalPages; start += 6) {
                const end = Math.min(start + 6, totalPages);
                const newDoc = await PDFDocument.create();
                const pages = await newDoc.copyPages(srcDoc, Array.from({ length: end - start }, (_, i) => start + i));
                pages.forEach(p => newDoc.addPage(p));
                const bytes = await newDoc.save();
                pdfChunksBase64.push({
                  data: Buffer.from(bytes).toString('base64'),
                  pages: `${start + 1}-${end}`,
                  block_index: pdfChunksBase64.length
                });
              }
            } catch (e) {
              pdfChunksBase64.push({ data: base64Full, pages: `1-${Math.min(6, pdfPages)}`, block_index: 0 });
            }
          }
        }
      } else if (ext === 'docx' || ext === 'doc') {
        const mammoth = require('mammoth');
        const result = await mammoth.extractRawText({ buffer });
        text = result.value || '';
      } else if (['txt', 'md', 'csv'].includes(ext)) {
        text = buffer.toString('utf-8');
      }
    }
  } catch (err) {
    text = `[EXTRACTION_ERROR] ${err.message}`;
  }

  results.push({
    json: {
      ...item.json,
      extracted_text: text,
      text_length: text.length,
      pdf_pages: pdfPages,
      needs_ocr: text.startsWith('[OCR_NEEDED]'),
      pdf_chunks_base64: pdfChunksBase64,
      pdf_block_count: pdfChunksBase64.length
    }
  });
}

return results;

// Text in Chunks aufteilen

const text = $input.first().json.extracted_text || '';
const chunkSize = parseInt($env.CHUNK_SIZE) || 500;
const overlap = parseInt($env.CHUNK_OVERLAP) || 75;

if (!text || text.length < 10) {
  return [{ json: { skip: true, reason: 'Kein Text' } }];
}

const chunks = [];
let start = 0;
let index = 0;

while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  let chunk = text.slice(start, end);

  if (end < text.length) {
    const lastPeriod = chunk.lastIndexOf('.');
    const lastNewline = chunk.lastIndexOf('\n');
    const cutPoint = Math.max(lastPeriod, lastNewline);
    if (cutPoint > chunkSize * 0.6) {
      chunk = chunk.slice(0, cutPoint + 1);
    }
  }

  const trimmed = chunk.trim();
  if (trimmed.length > 10) {
    chunks.push({
      json: {
        content: trimmed,
        chunk_index: index,
        file_name: $input.first().json.file_name,
        source_id: $input.first().json.source_id,
        source: $input.first().json.source || 'google_drive',
        mime_type: $input.first().json.mime_type || '',
        file_path: $input.first().json.file_path || '',
        source_modified_at: $input.first().json.modified_at || new Date().toISOString()
      }
    });
    index++;
  }

  start += trimmed.length - overlap;
  if (start <= 0 && index > 0) break;
}

return chunks;

// Embedding generieren — mit Gemini Multimodal fuer gescannte PDFs

const item = $input.first().json;
const provider = ($env.EMBEDDING_PROVIDER || 'ollama').toLowerCase();
const content = item.content;
const needsOcr = item.needs_ocr || false;
const pdfChunks = item.pdf_chunks_base64 || [];
const dim = parseInt($env.EMBEDDING_DIMENSION) || 768;
const apiKey = $env.GOOGLE_AI_API_KEY;

// --- Gescanntes PDF → Gemini Embedding 2 (multimodal) ---
if (needsOcr && pdfChunks.length > 0 && apiKey) {
  const results = [];
  for (const block of pdfChunks) {
    try {
      const res = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-2-preview:embedContent?key=${apiKey}`,
        body: {
          model: 'models/gemini-embedding-2-preview',
          content: { parts: [{ inline_data: { mime_type: 'application/pdf', data: block.data } }] },
          output_dimensionality: dim
        },
        json: true
      });
      results.push({
        json: {
          ...item,
          content: `[PDF Seiten ${block.pages}] ${item.file_name}`,
          chunk_index: block.block_index,
          embedding: '[' + res.embedding.values.join(',') + ']',
          embedding_method: 'gemini-multimodal'
        }
      });
      await new Promise(r => setTimeout(r, 1500));
    } catch (err) {
      results.push({ json: { ...item, embedding_error: `Block ${block.pages}: ${err.message}` } });
    }
  }
  return results;
}

// --- Text-Dokumente → normales Embedding ---
let embedding = [];
try {
  if (provider === 'ollama') {
    const url = $env.OLLAMA_BASE_URL || 'http://localhost:11434';
    const model = $env.EMBEDDING_MODEL || 'nomic-embed-text';
    const res = await this.helpers.httpRequest({
      method: 'POST', url: `${url}/api/embeddings`,
      body: { model, prompt: content }, json: true
    });
    embedding = res.embedding;
  } else if (provider === 'google') {
    const model = $env.GOOGLE_EMBEDDING_MODEL || 'gemini-embedding-001';
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/${model}:embedContent?key=${apiKey}`,
      body: { model: `models/${model}`, content: { parts: [{ text: content }] }, taskType: 'RETRIEVAL_DOCUMENT', output_dimensionality: dim },
      json: true
    });
    embedding = res.embedding.values;
  } else if (provider === 'openai') {
    const openaiKey = $env.OPENAI_API_KEY;
    const model = $env.EMBEDDING_MODEL || 'text-embedding-3-small';
    const res = await this.helpers.httpRequest({
      method: 'POST', url: 'https://api.openai.com/v1/embeddings',
      headers: { 'Authorization': `Bearer ${openaiKey}` },
      body: { model, input: content }, json: true
    });
    embedding = res.data[0].embedding;
  }
} catch (err) {
  return [{ json: { ...item, embedding_error: err.message } }];
}

await new Promise(r => setTimeout(r, 2000));
return [{ json: { ...item, embedding: '[' + embedding.join(',') + ']', embedding_method: provider } }];

